def equal_opportunity(
    predictions: dict[str, list[int]],
    ground_truth: dict[str, list[int]],
    tolerance: float = 0.05,
) -> list[FairnessResult]:
    """
    Check equal opportunity (TPR equality) across groups.
    predictions and ground_truth are parallel lists per group.
    """
    def tpr(preds: list[int], labels: list[int]) -> float:
        positives = [(p, y) for p, y in zip(preds, labels) if y == 1]
        if not positives:
            return float("nan")
        return sum(p for p, _ in positives) / len(positives)

    tprs = {g: tpr(predictions[g], ground_truth[g]) for g in predictions}
    groups = sorted(tprs.keys())
    results = []
    for i, a in enumerate(groups):
        for b in groups[i+1:]:
            diff = abs(tprs[a] - tprs[b])
            results.append(FairnessResult(
                metric="equal_opportunity",
                group_a=a,
                group_b=b,
                value_a=round(tprs[a], 4),
                value_b=round(tprs[b], 4),
                difference=round(diff, 4),
                passes=diff <= tolerance,
            ))
    return results

import numpy as np

def calibration_by_group(
    scores: dict[str, list[float]],     # group -> list of predicted probabilities [0, 1]
    labels: dict[str, list[int]],       # group -> list of ground-truth labels
    n_bins: int = 10,
) -> dict[str, list[dict]]:
    """
    Compute calibration curve per group.
    Returns {group: [{bin_center, mean_predicted, fraction_positive, count}]}.
    """
    results = {}
    bin_edges = np.linspace(0, 1, n_bins + 1)

    for group in scores:
        s = np.array(scores[group])
        y = np.array(labels[group])
        bin_data = []
        for lo, hi in zip(bin_edges[:-1], bin_edges[1:]):
            mask = (s >= lo) & (s < hi)
            if mask.sum() == 0:
                continue
            bin_data.append({
                "bin_center": round(float((lo + hi) / 2), 2),
                "mean_predicted": round(float(s[mask].mean()), 3),
                "fraction_positive": round(float(y[mask].mean()), 3),
                "count": int(mask.sum()),
            })
        results[group] = bin_data
    return results

def max_calibration_error_gap(
    cal_a: list[dict], cal_b: list[dict]
) -> float:
    """
    Maximum difference in (fraction_positive - mean_predicted) between two groups,
    across shared bins. > 0.1 is considered poor cross-group calibration.
    """
    def ece_per_bin(bins: list[dict]) -> dict[float, float]:
        return {b["bin_center"]: b["fraction_positive"] - b["mean_predicted"] for b in bins}

    errors_a = ece_per_bin(cal_a)
    errors_b = ece_per_bin(cal_b)
    shared = set(errors_a) & set(errors_b)
    if not shared:
        return float("nan")
    return max(abs(errors_a[c] - errors_b[c]) for c in shared)
